import { PropsBorderWidthCore } from './type.borderWidth';
import { PropsButtonCore } from './type.button';
import { PropsCheckboxCore } from './type.checkbox';
import { PropsColorsCore } from './type.colors';
import { PropsDropDownCore } from './type.dropDown';
import {
  PropsIconsNameCore,
  PropsSizeIconCore,
  PropsStyleIconCore,
} from './type.icon';
import { PropsRadiusCore } from './type.radius.d';
import { PropsShadowCore } from './type.shadow';
import { PropsTextCore, PropsTextDefault } from './type.text';
import { PropsToggleCore } from './type.toggle';

export interface PropsThemeDefault {
  colors: PropsColorsCore;
  icons: PropsIconsNameCore;
  styleText?: PropsTextDefault;
  font?: propsTypeFonts;
  fontSize?: FontSizeProps;
  fontWeight?: FontWeightsProps;
  borderRadius?: PropsRadiusCore;
  borderWidth?: PropsBorderWidthCore;
  opacityLevel?: PropsOpacityLevel;
  lineHeight?: PropsLineHight;
  styleButton?: PropsButtonCore;
  styleTextInput?: PropsStyleTextInput;
  styleRadio?: PropsStyleRadio;
  styleBackground?: PropsStyleBackground;
  spaces?: PropsSpaces;
  shadow?: PropsShadowCore;
  styleCheckbox?: PropsCheckboxCore;
  styleToggle?: PropsToggleCore;
  styleIcon?: PropsStyleIconCore;
  styleDropDown?: PropsDropDownCore;
}

interface PropsSpaces {
  margins: {
    flat: {
      quark: number;
      nano: number;
      xxxxs: number;
      xxxs: number;
      xxs: number;
      xs: number;
      tiny: number;
      smaller: number;
      small: number;
      middle: number;
      meddium: number;
      large: number;
      larger: number;
      xl: number;
      xxl: number;
      xxxl: number;
      huge: number;
    };
    standing: {
      quark: number;
      nano: number;
      xs: number;
      smaller: number;
      small: number;
      middle: number;
      medium: number;
      large: number;
      larger: number;
    };
  };
  padding: {
    inner: {
      small: string;
      middle: string;
      medium: string;
      large: string;
      larger: string;
      xl: string;
      xxxl: string;
      great: string;
