    squish: {
      xxxs: string;
      xxs: string;
      xs: string;
      quarck: string;
      smaller: string;
      small: string;
      xxxss: string;
      short: string;
      middle: string;
      minor: string;
      medium: string;
      large: string;
    };
    stretch: {
      small: string;
      middle: string;
      medium: string;
      large: string;
      larger: string;
      half: string;
      gSized: string;
    };
  };
}

interface PropsStyleBackground {
  default: {
    bgColor: string;
  };
  secundary: {
    bgColor: string;
  };
  scrim: {
    bgColor: string;
