    label: {
      type: PropsTextCore;
      textColor: string;
      errorTextColor: string;
      padding: number;
    };
    description: {
      type: PropsTextCore;
      textColor: string;
      errorTextColor: string;
      spacing: string;
    };
    shape: {
      backgroundColor: string;
