      name: string;
      errorColor: string;
      passwordColor: string;
    };
  };
  small: {
    width: number | string;
    height: number | string;
    backgroundColor: string;
    text: {
      type: PropsTextCore;
      textColor: string;
      errorTextColor: string;
    };
    label: {
